generated_oml:
// Sensing Components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor on motor to measure electrical current"
    DTDFVocab:producedData MotorCurrentDataTransmission
]
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder directly on the motor to measure shaft position"
    DTDFVocab:producedData MotorEncoderDataTransmission
]
instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox rear encoder to measure output shaft position"
    DTDFVocab:producedData GearboxEncoderDataTransmission
]
instance OutputAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Output angle sensor on first axis of MABI MAX 100 robot"
    DTDFVocab:producedData OutputAngleDataTransmission
]

// Data Transmitted
instance MotorCurrentDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]
instance MotorEncoderDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]
instance GearboxEncoderDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]
instance OutputAngleDataTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OutputAngleSensor
]

// Data
instance CurrentData : DTDFVocab:Data [
    base:desc "Electrical current measured by MotorCurrentSensor"
