    DTDFVocab:fromData MotorCurrentDataTransmission
]
instance TorqueData : DTDFVocab:Data [
    base:desc "Torque calculated from motor current and motor model"
    DTDFVocab:inputTo SimulationEnvironmentEnabler
    DTDFVocab:fromData MotorCurrentDataTransmission
]
instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity derived from motor/gearbox output speed"
    DTDFVocab:inputTo SimulationEnvironmentEnabler
    DTDFVocab:fromData OutputAngleDataTransmission
]
instance AccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration calculated from angular velocity changes"
    DTDFVocab:inputTo SimulationEnvironmentEnabler
    DTDFVocab:fromData OutputAngleDataTransmission
]
instance MotorOutputData : DTDFVocab:Data [
    base:desc "Motor output torque and speed from Simulink simulation"
    DTDFVocab:inputTo SimulationEnvironmentEnabler
    DTDFVocab:fromData MotorCurrentDataTransmission
]
instance GearwheelOutputData : DTDFVocab:Data [
    base:desc "Gearwheel output torque and speed from Simulink simulation"
    DTDFVocab:inputTo SimulationEnvironmentEnabler
    DTDFVocab:fromData GearboxEncoderDataTransmission
]
instance SystemOutputData : DTDFVocab:Data [
    base:desc "Overall robot axis output torque and speed from Simulink simulation"
    DTDFVocab:inputTo SimulationEnvironmentEnabler
    DTDFVocab:fromData OutputAngleDataTransmission
]

