instance SysMLModelingToolEnabler : DTDFVocab:Enabler [
    base:desc "SysML modeling tool for structural analysis of motor and gearbox"
    DTDFVocab:enables ModelingService
]
instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell enabling standardized asset description"
    DTDFVocab:enables AssetDescriptionService
]
instance DashboardVisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard visualization platform for real‑time monitoring"
    DTDFVocab:enables RealTimeVisualizationService
]

