instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization dashboard of current, torque, angular velocity, and acceleration"
    DTDFVocab:provides RealTimeVisualizationInsight
]
instance JointFrictionIdentificationService : DTDFVocab:Service [
