]
instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Estimation and update of friction parameters to improve robot motion accuracy"
    DTDFVocab:provides FrictionParameterUpdateInsight, ControlAccuracyImprovementAction
]
instance ModelingService : DTDFVocab:Service [
    base:desc "Development of SysML structural models for motor and gearbox"
]
instance AssetDescriptionService : DTDFVocab:Service [
    base:desc "Standardized asset description via Asset Administration Shell"
]

