    base:desc "Comparison of measured vs. simulated data to refine joint friction models"
]
instance FrictionParameterUpdateInsight : DTDFVocab:Insight [
    base:desc "Estimation and update of friction parameters to improve robot motion accuracy"
]
instance RealTimeVisualizationInsight : DTDFVocab:Insight [
    base:desc "Real‑time dashboard of current, torque, angular velocity, and acceleration"
]

